external_knowledge:
- 'Proteas' refers to the South African national cricket team;
- 'Half-century mark' means averages over 50 runs;
- The term 'typical run tallies' refers to the average runs scored, which in this context is calculated specifically against South Africa for batsmen.

sql:
SELECT AVG(player_max_highest_score) AS average_highest_score
FROM (
    SELECT MAX(highest_score) AS player_max_highest_score
    FROM performances
    GROUP BY player_id
) AS subquery;

external_knowledge:
- "standout performances" refers to the maximum runs and wickets taken by a player;
- "details about their team's leadership" includes the coach and captain names of the team;
- "top three" indicates the highest ranks in terms of runs and wickets.

sql:
SELECT SUM(runs) AS total_runs
FROM performances
WHERE match_id = 1;

SELECT p.name, p.team, pf.match_id
FROM players p
JOIN performances pf ON p.player_id = pf.player_id
WHERE pf.runs = (
    SELECT MAX(runs) FROM performances
);
